long long solve(std::vector<long long> prices, std::vector<long long> strategy, long long k) {
    long long n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    std::vector<long long> A(n);
    std::vector<long long> B(n);
    for (int i = 0; i < n; ++i) {
        A[i] = -strategy[i] * prices[i];
        B[i] = (1 - strategy[i]) * prices[i];
    }

    std::vector<long long> prefixA(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefixA[i + 1] = prefixA[i] + A[i];
    }

    std::vector<long long> prefixB(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    long long max_delta = 0;
    long long m = k / 2;
    for (int i = 0; i <= n - k; ++i) {
        int first_half_end = i + m - 1;
        int second_half_start = i + m;
        int second_half_end = i + k - 1;

        long long sumA = prefixA[first_half_end + 1] - prefixA[i];
        long long sumB = prefixB[second_half_end + 1] - prefixB[second_half_start];
        long long delta = sumA + sumB;

        if (delta > max_delta) {
            max_delta = delta;
        }
    }

    return original_profit + std::max(0LL, max_delta);
}

