    const prefixB = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    const m = k / 2;
    let max_delta = 0;

    for (let i = 0; i <= n - k; i++) {
        const first_half_end = i + m - 1;
        const second_half_start = i + m;
        const second_half_end = i + k - 1;

        const sumA = prefixA[i + m] - prefixA[i];
        const sumB = prefixB[i + k] - prefixB[second_half_start];

        const delta = sumA + sumB;

